// Compile morning briefing
const calendar = $input.first().json.calendar;
const analyses = $input.first().json.analyses;
const account = $input.first().json.account;
const schedule = $input.first().json.kill_zone_schedule;
const macro = $input.first().json;

let briefing = `📊 **MORNING INTELLIGENCE BRIEFING** 📊
`;
briefing += `━━━━━━━━━━━━━━━━━━━━━━━\n\n`;

briefing += `🗓️ **TODAY'S CALENDAR**\n`;
calendar.forEach(e => {
  briefing += `${e.time} ${e.currency} ${e.event} [${e.impact}]\n`;
});
briefing += `\n`;

briefing += `📈 **Overnight SMC Setups**\n`;
Object.entries(analyses).forEach(([sym, a]) => {
  briefing += `${sym}: ${a.bias} | ${a.setups.length} setups\n`;
});
briefing += `\n`;

briefing += `💼 **Portfolio Status**\n`;
briefing += `Balance: $${account.balance.toFixed(2)}\n`;
briefing += `Daily P&L: $${account.daily_pnl.toFixed(2)}\n`;
briefing += `Open Positions: ${account.open_positions}\n\n`;

briefing += `⏰ **Kill Zone Schedule**\n`;
schedule.forEach(s => {
  briefing += `${s.time} ${s.session}\n`;
});
briefing += `\n`;

briefing += `🌍 **Macro Regime**: ${macro.regime}\n`;
briefing += `Confidence: ${(macro.confidence * 100).toFixed(0)}%\n\n`;

briefing += `━━━━━━━━━━━━━━━━━━━━━━━\n`;
briefing += `Good luck trading! 🎯`;

return { briefing, chatId: '-100123456789' };
